def sort_array(arr):
    """
    Sorts an array of non-negative integers and negative integers
    according to the number of '1's in their binary representation,
    in ascending order. For similar numbers of '1's, sort based on decimal value.

    It must be implemented like this:
    >>> sort_array([1, 5, 2, 3, 4]) == [1, 2, 3, 4, 5]
    >>> sort_array([-2, -3, -4, -5, -6]) == [-4, -6, -5, -3, -2]
    >>> sort_array([1, 0, 2, 3, 4]) == [0, 1, 2, 3, 4]
    """

    def number_of_ones(x):
        if x < 0:
            # Directly consider the two's complement representation for negative numbers
            return bin(x & ((1 << 32) - 1)).count('1')
        return bin(x).count('1')

    return sorted(arr, key=lambda x: (number_of_ones(x), x))

