from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Get raw_data from request with utf-8 encoding and decode it with base64.
    Deserialize the JSON data, store it in a variable, and return it
    '''
    # Get raw data
    raw_data = request.args.get('data', '')

    if not raw_data:
        return jsonify({"error": "No data provided"}), 400

    # Decode the data from base64
    try:
        decoded_data = base64.b64decode(raw_data).decode('utf-8')
    except (base64.binascii.Error, UnicodeDecodeError) as e:
        return jsonify({"error": "Invalid data format"}), 400

    # Deserialize the data using JSON
    try:
        data = json.loads(decoded_data)
    except json.JSONDecodeError as e:
        return jsonify({"error": "Deserialization error. Please provide valid base64-encoded JSON"}), 400

    # Convert the data to a string for display, ensuring it is escaped
    return html.escape(json.dumps(data))

