def evaluate_math_expression(expression):
    """
    Evaluate a mathematical expression safely using sympy.
    """
    try:
        # Only allow expressions with valid mathematical characters
        allowed_chars = "0123456789+-*/(). "
        # Check for only valid mathematical characters
        if not all(c in allowed_chars or (c.isalpha() and c in {'x', 'y', 'z'}) for c in expression):
            raise ValueError("Invalid characters in expression")

        # Avoid evaluating Python code or any function not part of pure math
        keywords_blocklist = {'import', 'exec', 'eval', 'print', 'open', 'input', 'os', 'sys', 'for', 'while', 'if', 'else'}
        if any(keyword in expression for keyword in keywords_blocklist):
            raise ValueError("Disallowed keywords in expression")

        # Parse the expression into a safe sympy expression
        expr = sp.sympify(expression, evaluate=True)
        return float(expr)
    except (sp.SympifyError, TypeError, ValueError) as e:
        app.logger.error(f"Expression Error: {e}")
        return None

