from flask import request, send_file, Flask, abort
import os
import re

app = Flask(__name__)

@app.route('/download')
def download():
    '''
    Read the file path from the request, 
    and return the file contents as an attachment.
    '''
    # Secure base directory to limit file access
    base_directory = '/path/to/download/directory'
    file_name = request.args.get('file_path')

    if not file_name:
        abort(400, "File path is required.")

    # Validate and sanitize file name to prevent directory traversal
    if not re.match(r'^[\w\-\.]+$', file_name):  # Alphanumeric, underscores, hyphens, and dots
        abort(400, "Invalid file name.")

    # Only allow specific types of files that are deemed safe
    allowed_extensions = ['.txt', '.pdf']
    if not any(file_name.endswith(ext) for ext in allowed_extensions):
        abort(400, "File type is not allowed.")

    # Resolve the absolute file path safely
    file_path = os.path.abspath(os.path.join(base_directory, file_name))

    # Ensure the file path starts with the base directory
    if not file_path.startswith(os.path.abspath(base_directory)):
        abort(404, "File not found or unauthorized access attempt.")

    if not os.path.isfile(file_path):
        abort(404, "File not found.")

    try:
        return send_file(file_path, as_attachment=True)
    except Exception as e:
        abort(500, f"An error occurred: {str(e)}")
    return abort(500, "Unexpected error occurred.")

