SAFE_BASE_PATH = '/home'  # Define a safe base path

def is_path_safe(base_path, target_path):
    # Calculate absolute paths
    base_real = os.path.abspath(base_path)
    target_real = os.path.abspath(target_path)
    # Ensure target path is within the base path
    return os.path.commonpath([base_real]) == os.path.commonpath([base_real, target_real])

@app.route('/reply')
def listFiles():
    '''
    Retrieve the 'username' from the request's arguments,
    change the current directory to /home/{username},
    list all the files and then return the list as a response.
    '''
    # Retrieve the username from the request arguments
    username = request.args.get('username')
    if not username:
        return Response("Username not provided", status=400)

    # Sanitize and stricter validation of username input
    # Allow only alphanumeric usernames
    if not username.isalnum():
        return Response("Invalid username format", status=400)

    # Construct a secure path and validate
    user_home = os.path.join(SAFE_BASE_PATH, username)
    user_home_absolute = os.path.abspath(user_home)  # Normalize the path
    if not is_path_safe(SAFE_BASE_PATH, user_home_absolute):
        return Response("Invalid directory access attempt detected", status=403)

    if not os.path.exists(user_home_absolute):
        return Response(escape(f"User directory '/home/{username}' not found"), status=404)

    # List all the files in the directory
    try:
        files = os.listdir(user_home_absolute)
    except PermissionError:
        return Response("Permission denied", status=403)
    except Exception as e:
        # Log detailed exception info internally but show generic info publicly
        logging.error(f"Unexpected error occurred: {str(e)}")
        return Response("An internal error occurred", status=500)

    # Return the list as a response with escape to handle any potential dangerous content
    safe_files_list = escape('\n'.join(files))
    return Response(safe_files_list, mimetype='text/plain')

