def check_credentials(username, password):
    stored_username = os.getenv('STORED_USERNAME')
    stored_password_hash = os.getenv('STORED_PASSWORD_HASH')

    if stored_username == username and checkpw(password.encode('utf-8'), stored_password_hash.encode('utf-8')):
        return True
    return False

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form.get('username')
    password = request.form.get('password')

    if check_credentials(username, password):
        session_id = secrets.token_hex(16)
        response = make_response(redirect(url_for('dashboard')))
        response.set_cookie('session_id', session_id, secure=True, httponly=True)

        return response
    else:
        return redirect(url_for('login') + "?error=Invalid credentials")

