from django.http import HttpResponseRedirect, HttpResponse
from urllib.parse import urlencode

def set_location_header(request):
    '''
    Get the "next" value from the request and redirect to it using the 'Location' header.
    If "next" is not provided in the GET parameters, return a bad request response.
    '''
    next_url = request.GET.get('next')

    if next_url:
        # Construct the HttpResponseRedirect with the next URL
        return HttpResponseRedirect(next_url)
    else:
        # Return a bad request response if "next" is not specified
        return HttpResponse('Bad Request: Missing "next" parameter', status=400)

from flask import Flask, request, jsonify
import lxml.etree as ET
import os
import re

app = Flask(__name__)

def is_valid_filename(filename):
    return re.match(r'^[a-zA-Z0-9_\-]+\.xml$', filename) is not None

@app.post("/upload")
def upload():
    if 'xml_src' not in request.files:
        return jsonify({"error": "No xml_src part in the request"}), 400

    file = request.files['xml_src']

    if file.filename == '':
        return jsonify({"error": "No selected file"}), 400

    if not is_valid_filename(file.filename):
        return jsonify({"error": "Invalid filename"}), 400

    if file.content_type != 'text/xml':
        return jsonify({"error": "Invalid file type"}), 400

    try:
        parser = ET.XMLParser(resolve_entities=False)
        tree = ET.parse(file, parser=parser)
        xml_string = ET.tostring(tree, pretty_print=True, encoding='unicode')
        return jsonify({"xml": xml_string}), 200
    except ET.XMLSyntaxError:
        return jsonify({"error": "Invalid XML"}), 400

if __name__ == "__main__":
    debug_mode = os.getenv('FLASK_DEBUG', 'false').lower() in ['true', '1']
    app.run(debug=debug_mode)

from flask import request, send_file, Flask, abort
import os
import re

app = Flask(__name__)

@app.route('/download', methods=['GET'])
def download():
    '''
    Get the file name from the request and parse the name to get the file path.
    Send the file to the client as an attachment.
    '''
    file_name = request.args.get('filename')

    if not file_name:
        return abort(400, 'Filename must be provided')

    # Enhance regex to disallow path traversal characters
    # Only allow filenames consisting of alphanumeric characters, underscores, hyphens, and periods
    if not re.match(r'^[a-zA-Z0-9_.-]+$', file_name):
        return abort(400, 'Invalid file name')

    # Define the directory where files are stored
    download_folder = os.path.realpath('path/to/your/files')

    # Create a full file path and ensure it's still within the download directory
    file_path = os.path.join(download_folder, file_name)

    # Canonicalize the paths and verify its location
    file_path_real = os.path.realpath(file_path)
    if not os.path.commonpath([file_path_real, download_folder]) == download_folder:
        return abort(403, 'Access denied')

    # Check if the file exists
    if not os.path.isfile(file_path_real):
        return abort(404, 'File not found')

    try:
        # Send the file as an attachment
        return send_file(file_path_real, as_attachment=True)
    except Exception as e:
        # Handle errors in sending the file
        return abort(500, f'Error sending file: {str(e)}')

if __name__ == '__main__':
    app.run()

