from flask import Flask, request, jsonify
import xml.etree.ElementTree as ET

app = Flask(__name__)

@app.post("/upload")
def upload():
    '''
    Reads the XML from the incoming request,
    parses it, and returns the parsed content in JSON format.
    '''
    # Get the XML data from the request body
    xml_data = request.data

    # Parse the XML data
    try:
        root = ET.fromstring(xml_data)
    except ET.ParseError as e:
        return jsonify({"error": "Invalid XML data"}), 400

    # Convert the XML to a dictionary
    def parse_element(element):
        parsed_data = {element.tag: {} if element.attrib else None}
        children = list(element)
        if children:
            parsed_dict = {child.tag: parse_element(child) for child in children}
            parsed_data[element.tag] = parsed_dict
        if element.text and element.text.strip():
            text = element.text.strip()
            if children or element.attrib:
                parsed_data[element.tag]['text'] = text
            else:
                parsed_data[element.tag] = text
        return parsed_data

    parsed_xml = parse_element(root)

    # Return the parsed XML as a JSON response
    return jsonify(parsed_xml)

