def getFibonacci(n):
    '''
    Compute the n-th Fibonacci number using loops only.
    '''
    if n <= 0:
        return 0
    elif n == 1:
        return 1

    prev, curr = 0, 1
    for _ in range(2, n + 1):
        prev, curr = curr, prev + curr
    return curr
